script.text:

function active$FormReason(f) {f.add_onResponseComplete(on$FormReason$ResponseComplete);}
function close$FormReason(f) {try {f.remove_onResponseComplete(on$FormReason$ResponseComplete)} catch (ex) {}}
function on$FormReason$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_nx');
      break;
    default:
      break;
  }
}

      &ScriptIrregular;
